_TMPL = ('<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" '
         'fill="none" stroke="{c}" stroke-width="{w}" stroke-linecap="round" '
         'stroke-linejoin="round">{body}</svg>')


def make_pixmap(name: str, color: str, px: int = 44, width: float = 2.0) -> QPixmap:
    body = LUCIDE.get(name, "").replace("currentColor", color)
    svg = _TMPL.format(c=color, w=width, body=body)
    renderer = QSvgRenderer(QByteArray(svg.encode("utf-8")))
    pm = QPixmap(px, px)
    pm.fill(Qt.transparent)
    p = QPainter(pm)
    p.setRenderHint(QPainter.Antialiasing)
    renderer.render(p)
    p.end()
    return pm


def make_icon(name: str, color: str, px: int = 44, width: float = 2.0) -> QIcon:
    return QIcon(make_pixmap(name, color, px, width))
